// First Fit Memory Allocation
// holes: list of available memory blocks with (start, size)
// processSize: size of memory requested

FUNCTION FirstFit(holes, processSize):
 FOR each hole IN holes:
 IF hole.size >= processSize THEN
 // Allocate memory
 allocatedAddress = hole.start
 remainingSize = hole.size - processSize

 // Update hole list
 REMOVE hole FROM holes

 IF remainingSize > 0 THEN
 // Create new smaller hole
 newHole = (hole.start + processSize, remainingSize)
 ADD newHole TO holes
 END IF

 RETURN allocatedAddress
 END IF
 END FOR

 // No suitable hole found
 RETURN -1 // Out of memory
END FUNCTION

// Paging Address Translation
// pageTable: array mapping page numbers to frame numbers
// pageSize: size of each page (must be power of 2)
// virtualAddress: the logical address from CPU

FUNCTION TranslateAddress(virtualAddress, pageTable, pageSize):
 // Calculate number of offset bits
 offsetBits = log2(pageSize)

 // Extract page number and offset from virtual address
 pageNumber = virtualAddress >> offsetBits
 offset = virtualAddress AND (pageSize - 1)

 // Check if page is valid using page table
 IF pageTable[pageNumber].valid == FALSE THEN
 // Page fault occurs
 HANDLE_PAGE_FAULT(pageNumber)
 END IF

 // Get frame number from page table
 frameNumber = pageTable[pageNumber].frameNumber

 // Calculate physical address
 physicalAddress = (frameNumber << offsetBits) + offset

 RETURN physicalAddress
END FUNCTION

